// "greet" adlı ox funksiyası yaradıram
const greet = (name) => {
  return "Salam, " + name + "!";
};
console.log(greet("Aysel")); // nəticə: Salam, Aysel!
console.log(greet("Kamran")); // nəticə: Salam, Kamran!

// İki ədədi toplayan ox funksiyası
const addNumbers = (a, b) => {
  return a + b;
};
console.log(addNumbers(5, 3)); // nəticə: 8

// Qısa sintaksis
const multiply = (a, b) => a * b;
console.log(multiply(4, 5)); // nəticə: 20

// Hoisting işləmir
// console.log(divide(10, 2)); // Xəta: Cannot access "divide" before initialization
const divide = (a, b) => a / b;

// Tək parametrli qısa ox funksiyası
const square = number => number * number;
console.log(square(5)); // nəticə: 25

// Çoxsətirli ox funksiyası
const sayHello = () => {
  console.log("Hello!");
  return "Salam mesajı göndərildi";
};
console.log(sayHello()); // nəticə: Hello! və Salam mesajı göndərildi

// Mağaza cəmi hesablama funksiyası
const calculateTotal = (price, quantity) => price * quantity;
console.log(calculateTotal(10, 2)); // nəticə: 20
console.log(calculateTotal(5, 4)); // nəticə: 20

// Praktik nümunə
const calculateArea = (width, height) => width * height;
console.log(calculateArea(5, 4)); // nəticə: 20
console.log(calculateArea(3, 6)); // nəticə: 18

