// Create an arrow function called "greet"
const greet = (name) => {
  return "Hello, " + name + "!";
};
console.log(greet("Aysel")); // Output: Hello, Aysel!
console.log(greet("Kamran")); // Output: Hello, Kamran!

// An arrow function to add two numbers
const addNumbers = (a, b) => {
  return a + b;
};
console.log(addNumbers(5, 3)); // Output: 8

// Short syntax
const multiply = (a, b) => a * b;
console.log(multiply(4, 5)); // Output: 20

// Hoisting doesn’t work
// console.log(divide(10, 2)); // Error: Cannot access "divide" before initialization
const divide = (a, b) => a / b;

// Single-parameter short arrow function
const square = number => number * number;
console.log(square(5)); // Output: 25

// Multi-line arrow function
const sayHello = () => {
  console.log("Hello!");
  return "Greeting sent";
};
console.log(sayHello()); // Output: Hello! and Greeting sent

// Calculate shopping total
const calculateTotal = (price, quantity) => price * quantity;
console.log(calculateTotal(10, 2)); // Output: 20
console.log(calculateTotal(5, 4)); // Output: 20

// Practical example
const calculateArea = (width, height) => width * height;
console.log(calculateArea(5, 4)); // Output: 20
console.log(calculateArea(3, 6)); // Output: 18

