// Создаём стрелочную функцию под названием "greet"
const greet = (name) => {
  return "Привет, " + name + "!";
};
console.log(greet("Айсель")); // Вывод: Привет, Айсель!
console.log(greet("Кямран")); // Вывод: Привет, Кямран!

// Стрелочная функция для сложения двух чисел
const addNumbers = (a, b) => {
  return a + b;
};
console.log(addNumbers(5, 3)); // Вывод: 8

// Короткий синтаксис
const multiply = (a, b) => a * b;
console.log(multiply(4, 5)); // Вывод: 20

// Hoisting не работает
// console.log(divide(10, 2)); // Ошибка: Cannot access "divide" before initialization
const divide = (a, b) => a / b;

// Короткая стрелочная функция с одним параметром
const square = number => number * number;
console.log(square(5)); // Вывод: 25

// Многострочная стрелочная функция
const sayHello = () => {
  console.log("Привет!");
  return "Приветствие отправлено";
};
console.log(sayHello()); // Вывод: Привет! и Приветствие отправлено

// Подсчёт общей стоимости покупок
const calculateTotal = (price, quantity) => price * quantity;
console.log(calculateTotal(10, 2)); // Вывод: 20
console.log(calculateTotal(5, 4)); // Вывод: 20

// Практический пример
const calculateArea = (width, height) => width * height;
console.log(calculateArea(5, 4)); // Вывод: 20
console.log(calculateArea(3, 6)); // Вывод: 18

